## Common patterns

### Settings toggle

Use switches for user preference settings that can be turned on or off.

```jsx live-dev
const App = () => {
  const [settings, setSettings] = React.useState({
    emailNotifications: true,
    pushNotifications: false,
    weeklyDigest: true,
  });

  return (
    <Stack gap="400">
      <Text fontSize="450" fontWeight="medium">
        Notification Settings
      </Text>
      <Switch
        isSelected={settings.emailNotifications}
        onChange={(value) =>
          setSettings({ ...settings, emailNotifications: value })
        }
      >
        Email notifications
      </Switch>
      <Switch
        isSelected={settings.pushNotifications}
        onChange={(value) =>
          setSettings({ ...settings, pushNotifications: value })
        }
      >
        Push notifications
      </Switch>
      <Switch
        isSelected={settings.weeklyDigest}
        onChange={(value) =>
          setSettings({ ...settings, weeklyDigest: value })
        }
      >
        Weekly digest emails
      </Switch>
    </Stack>
  );
};
```

### Feature enable/disable

Use switches to enable or disable application features.

```jsx live-dev
const App = () => {
  const [darkMode, setDarkMode] = React.useState(false);
  const [autoSave, setAutoSave] = React.useState(true);

  return (
    <Stack gap="400">
      <Text fontSize="450" fontWeight="medium">
        Editor Settings
      </Text>
      <Switch isSelected={darkMode} onChange={setDarkMode}>
        Dark mode
      </Switch>
      <Switch isSelected={autoSave} onChange={setAutoSave}>
        Auto-save
      </Switch>
      {autoSave && (
        <Text fontSize="350" color="neutral.11">
          Changes will be saved automatically every 30 seconds
        </Text>
      )}
    </Stack>
  );
};
```

### Conditional content display

Show or hide content based on switch state.

```jsx live-dev
const App = () => {
  const [showAdvanced, setShowAdvanced] = React.useState(false);

  return (
    <Stack gap="400">
      <Switch isSelected={showAdvanced} onChange={setShowAdvanced}>
        Show advanced options
      </Switch>
      {showAdvanced && (
        <Stack gap="300" p="400" bg="neutral.3" borderRadius="200">
          <Text fontSize="400" fontWeight="medium">
            Advanced Options
          </Text>
          <Text fontSize="350">
            Additional configuration options appear here
          </Text>
        </Stack>
      )}
    </Stack>
  );
};
```

## Testing your implementation

These examples demonstrate how to test your implementation when using Switch within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the Switch renders with expected elements and attributes

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Switch, NimbusProvider } from "@commercetools/nimbus";

describe("Switch - Basic rendering", () => {
  it("renders with label", () => {
    render(
      <NimbusProvider>
        <Switch>Enable notifications</Switch>
      </NimbusProvider>
    );

    expect(screen.getByText("Enable notifications")).toBeInTheDocument();
    expect(screen.getByRole("switch")).toBeInTheDocument();
  });

  it("renders without visible label using aria-label", () => {
    render(
      <NimbusProvider>
        <Switch aria-label="Toggle feature" />
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).toHaveAccessibleName("Toggle feature");
  });
});
```

### Interaction Tests

Test user interactions with the Switch

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Switch, NimbusProvider } from "@commercetools/nimbus";

describe("Switch - Interactions", () => {
  it("toggles when clicked", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <Switch onChange={handleChange}>Toggle me</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).not.toBeChecked();

    await user.click(switchElement);
    expect(handleChange).toHaveBeenCalledWith(true);
  });

  it("toggles with keyboard (Space)", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <Switch onChange={handleChange}>Keyboard toggle</Switch>
      </NimbusProvider>
    );

    // Use userEvent.tab() instead of element.focus() to avoid act() warnings
    await user.tab();
    await user.keyboard(" ");
    expect(handleChange).toHaveBeenCalledWith(true);
  });

  it("maintains state through multiple toggles", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <Switch defaultSelected={false}>Multi-toggle</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).not.toBeChecked();

    await user.click(switchElement);
    expect(switchElement).toBeChecked();

    await user.click(switchElement);
    expect(switchElement).not.toBeChecked();
  });

  it("can be focused with Tab key", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <Switch>Focusable switch</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");

    await user.tab();
    expect(switchElement).toHaveFocus();
  });
});
```

### Controlled Mode Tests

Test controlled state management

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Switch, NimbusProvider } from "@commercetools/nimbus";

describe("Switch - Controlled mode", () => {
  it("respects controlled isSelected prop", () => {
    const { rerender } = render(
      <NimbusProvider>
        <Switch isSelected={false}>Controlled switch</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).not.toBeChecked();

    rerender(
      <NimbusProvider>
        <Switch isSelected={true}>Controlled switch</Switch>
      </NimbusProvider>
    );

    expect(switchElement).toBeChecked();
  });

  it("calls onChange with new value", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <Switch isSelected={false} onChange={handleChange}>
          Controlled switch
        </Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    await user.click(switchElement);

    expect(handleChange).toHaveBeenCalledWith(true);
  });

  it("updates when isSelected prop changes", () => {
    const { rerender } = render(
      <NimbusProvider>
        <Switch isSelected={false}>Toggle</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).not.toBeChecked();

    rerender(
      <NimbusProvider>
        <Switch isSelected={true}>Toggle</Switch>
      </NimbusProvider>
    );

    expect(switchElement).toBeChecked();
  });
});
```

### Uncontrolled Mode Tests

Test uncontrolled state management with defaultSelected

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Switch, NimbusProvider } from "@commercetools/nimbus";

describe("Switch - Uncontrolled mode", () => {
  it("uses defaultSelected for initial state", () => {
    render(
      <NimbusProvider>
        <Switch defaultSelected={true}>Default on</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).toBeChecked();
  });

  it("manages its own state after initial render", async () => {
    const user = userEvent.setup();

    render(
      <NimbusProvider>
        <Switch defaultSelected={false}>Uncontrolled</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).not.toBeChecked();

    await user.click(switchElement);
    expect(switchElement).toBeChecked();

    await user.click(switchElement);
    expect(switchElement).not.toBeChecked();
  });
});
```

### State Tests

Test different component states (disabled, invalid, readonly)

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Switch, NimbusProvider } from "@commercetools/nimbus";

describe("Switch - States", () => {
  it("renders in disabled state", () => {
    render(
      <NimbusProvider>
        <Switch isDisabled>Disabled switch</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).toBeDisabled();
  });

  it("does not respond to clicks when disabled", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <Switch isDisabled onChange={handleChange}>
          Disabled
        </Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    await user.click(switchElement);

    expect(handleChange).not.toHaveBeenCalled();
  });

  it("renders in invalid state", () => {
    render(
      <NimbusProvider>
        <Switch isInvalid>Invalid switch</Switch>
      </NimbusProvider>
    );

    const switchRoot = screen
      .getByText("Invalid switch")
      .closest("[data-slot='root']");
    expect(switchRoot).toHaveAttribute("data-invalid", "true");
  });

  it("renders in readonly state", () => {
    render(
      <NimbusProvider>
        <Switch isReadOnly isSelected={true}>
          Read-only switch
        </Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).toHaveAttribute("aria-readonly", "true");
  });

  it("does not toggle when readonly", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <Switch isReadOnly isSelected={false} onChange={handleChange}>
          Read-only
        </Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    await user.click(switchElement);

    expect(handleChange).not.toHaveBeenCalled();
  });
});
```

### Accessibility Tests

Verify accessibility attributes and keyboard navigation

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { Switch, NimbusProvider } from "@commercetools/nimbus";

describe("Switch - Accessibility", () => {
  it("has proper switch role", () => {
    render(
      <NimbusProvider>
        <Switch>Accessible switch</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).toBeInTheDocument();
  });

  it("has accessible name from label", () => {
    render(
      <NimbusProvider>
        <Switch>Enable feature</Switch>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).toHaveAccessibleName("Enable feature");
  });

  it("has accessible name from aria-label", () => {
    render(
      <NimbusProvider>
        <Switch aria-label="Toggle notifications" />
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).toHaveAccessibleName("Toggle notifications");
  });

  it("supports aria-labelledby", () => {
    render(
      <NimbusProvider>
        <div>
          <span id="switch-label">Custom label</span>
          <Switch aria-labelledby="switch-label" />
        </div>
      </NimbusProvider>
    );

    const switchElement = screen.getByRole("switch");
    expect(switchElement).toHaveAccessibleName("Custom label");
  });
});
```

